 * @Description : 개인정보 조회 이력 관리를 위한 VO 클래스
 * @Modification Information
 *
 *    수정일         수정자         수정내용
 *    -------        -------     -------------------
 *    2014.09.11	표준프레임워크		최초생성
* @author Vincent Han
 * @since 2014.09.11
 * @version 3.5
 */
public class PrivacyLog implements Serializable {

	/**
	 * Default Serial Version UID
	 */
	private static final long serialVersionUID = 1L;

	/** 요청 ID (REQUST_ID) */
	private String requestId = "";

	/** 조회일시 (INQIRE_DT) */
	private String inquiryDatetime = "";

	/** 서비스 명 (SRVC_NM) */
	private String serviceName = "";

	/** 조회 정보 명 (INQIRE_INFO) */
	private String inquiryInfo = "";

	/** 요청자아이디 (RQESTER_ID) */
	private String requesterId = "";	

	/** 요청자 이름 (RQESTER_NM) */
	private String requesterName = "";

	/** 요청아이피 (RQESTER_IP) */
	private String requesterIp = "";

	/** 검색조건 */
	private String searchCondition = "";	

	/** 검색시작일 */
	private String searchBeginDate = "";

	/** 검색종료일 */
	private String searchEndDate = "";

	/** 검색시작일 (화면용) */
	private String searchBeginDateView = "";	// ex: 2014.09.14

	/** 검색종료일 (화면용) */
	private String searchEndDateView = "";	// ex: 2014.09.14	

	/** 검색단어 */
	private String searchWord = "";

	/** 정렬순서 (DESC, ASC) */
	private String sortOrder = "";

	/** 검색사용여부 */
    private String searchUseYn = "";

    /** 현재페이지 */
    private int pageIndex = 1;

    /** 페이지개수 */
    private int pageUnit = 10;

    /** 페이지사이즈 */
    private int pageSize = 10;

    /** firstIndex */
    private int firstIndex = 1;

    /** lastIndex */
    private int lastIndex = 1;

    /** recordCountPerPage */
    private int recordCountPerPage = 10;

	}

	/**
	 * 개인정보조회 로그 상세 조회
	 *
	 * @param privacyLog
	 * @param model
	 * @return sym/log/plg/EgovPrivacyLogInqire
	 * @throws Exception
	 */
	@RequestMapping(value = "/sym/log/plg/SelectPrivacyLogDetail.do")
	public String selectWebLog(@ModelAttribute("searchVO") PrivacyLog privacyLog,
			ModelMap model) throws Exception{

		model.addAttribute("result", privacyLogService.selectPrivacyLog(privacyLog));

		return "egovframework/com/sym/log/plg/EgovPrivacyLogDetail";
	}

}
